const query = $('Webhook').item.json.query || {};
const productId = query.product_id;
const queryAll = query.all === 'true';

const items = $input.all();
let filtered;

if (productId !== undefined && productId !== null && productId !== '' && productId !== '0' && productId !== 0) {
  // Query a single product ID
  const pid = parseInt(productId);
  const match = items.find(item => item.json.id === pid);
  if (match) {
    return [{
      json: {
        is_single: true,
        data: {
          id: match.json.id,
          status: match.json.status,
          sound_prompt: match.json.sound_prompt,
          video: match.json.video,
          final_video: match.json.final_video
        }
      }
    }];
  } else {
    return [{
      json: {
        is_single: true,
        data: {
          status: 'not_found',
          sound_prompt: null,
          video: null,
          final_video: null
        }
      }
    }];
  }
}

// Otherwise return list of items
if (queryAll) {
  // Return all rows sorted by ID descending (history view) - include picture_url and audio_url for delete modal
  filtered = items
    .map(item => ({
      id: item.json.id,
      createdAt: item.json.createdAt,
      prouduct_description: item.json.prouduct_description,
      sound_prompt: item.json.sound_prompt,
      image_url2: item.json.image_url2,
      status: item.json.status,
      final_video: item.json.final_video,
      video: item.json.video,
      picture_url: item.json.picture_url || '',
      audio_url: item.json.audio_url || ''
    }))
    .sort((a, b) => b.id - a.id);
} else {
  // Original unmerged jobs logic (limit 10) - checks for 'done' or 'success'
  filtered = items
    .filter(item => (item.json.status === 'done' || item.json.status === 'success') && (item.json.final_video === 'wait' || !item.json.final_video))
    .map(item => ({
      id: item.json.id,
      createdAt: item.json.createdAt,
      prouduct_description: item.json.prouduct_description,
      sound_prompt: item.json.sound_prompt,
      image_url2: item.json.image_url2
    }))
    .sort((a, b) => b.id - a.id)
    .slice(0, 10);
}

return [{
  json: {
    is_single: false,
    items: filtered
  }
}];
